class Solution:
    def minimumChanges(self, s: str, k: int) -> int:
        n = len(s)
        # Precompute cost to make each substring s[i:j] a semi-palindrome
        cost = [[0] * (n + 1) for _ in range(n + 1)]

        for i in range(n):
            for j in range(i + 1, n + 1):
                sub = s[i:j]
                len_sub = j - i
                min_cost = float('inf')

                # Try all possible d values for semi-palindrome
                for d in range(1, len_sub):
                    if len_sub % d != 0:
                        continue
                    groups = len_sub // d
                    total = 0
                    for g in range(groups):
                        # Check each group of size d
                        for pos in range(g, len_sub, groups):
                            total += 1 - (1 if s[i + pos] == s[i + g] else 0)
                    min_cost = min(min_cost, total)

                cost[i][j] = min_cost

        # Dynamic programming to partition the string into k substrings
        dp = [[float('inf')] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = 0

        for i in range(1, n + 1):
            for parts in range(1, k + 1):
                for j in range(1, i):
                    dp[i][parts] = min(dp[i][parts], dp[j][parts - 1] + cost[j][i])

        return dp[n][k]
